protected AxisState drawLabel(String label, Graphics2D g2, 
        Rectangle2D plotArea, Rectangle2D dataArea, RectangleEdge edge, 
        AxisState state, PlotRenderingInfo plotState) {

    // Check for a null 'state' argument
    if (state == null) {
        throw new IllegalArgumentException("Null 'state' argument.");
    }

    // Early return if label is null or empty
    if (label == null || label.isEmpty()) {
        return state;
    }

    Font font = getLabelFont();
    RectangleInsets insets = getLabelInsets();
    g2.setFont(font);
    g2.setPaint(getLabelPaint());
    FontMetrics fm = g2.getFontMetrics();
    Rectangle2D labelBounds = TextUtilities.getTextBounds(label, g2, fm);
    Shape hotspot = null;

    // Common calculations for label width and height
    float w = (float) labelBounds.getWidth();
    float h = (float) labelBounds.getHeight();
    float labelx = (float) dataArea.getCenterX();

    switch (edge) {
        case TOP:
            float labelyTop = (float) (state.getCursor() - insets.getBottom() - h / 2.0);
            drawRotatedLabel(label, g2, labelx, labelyTop, getLabelAngle(), labelBounds);
            hotspot = new Rectangle2D.Float(labelx - w / 2.0f, labelyTop - h / 2.0f, w, h);
            state.cursorUp(insets.getTop() + h + insets.getBottom());
            break;

        case BOTTOM:
            float labelyBottom = (float) (state.getCursor() + insets.getTop() + h / 2.0);
            drawRotatedLabel(label, g2, labelx, labelyBottom, getLabelAngle(), labelBounds);
            hotspot = new Rectangle2D.Float(labelx - w / 2.0f, labelyBottom - h / 2.0f, w, h);
            state.cursorDown(insets.getTop() + h + insets.getBottom());
            break;

        case LEFT:
            float labelyLeft = (float) dataArea.getCenterY();
            float labelxLeft = (float) (state.getCursor() - insets.getRight() - w / 2.0);
            drawRotatedLabel(label, g2, labelxLeft, labelyLeft, getLabelAngle() - Math.PI / 2.0, labelBounds);
            hotspot = new Rectangle2D.Float(labelxLeft - w / 2.0f, labelyLeft - h / 2.0f, w, h);
            state.cursorLeft(insets.getLeft() + w + insets.getRight());
            break;

        case RIGHT:
            float labelyRight = (float) dataArea.getCenterY();
            float labelxRight = (float) (state.getCursor() + insets.getLeft() + w / 2.0);
            drawRotatedLabel(label, g2, labelxRight, labelyRight, getLabelAngle() + Math.PI / 2.0, labelBounds);
            hotspot = new Rectangle2D.Float(labelxRight - w / 2.0f, labelyRight - h / 2.0f, w, h);
            state.cursorRight(insets.getLeft() + w + insets.getRight());
            break;
    }

    if (plotState != null && hotspot != null) {
        ChartRenderingInfo owner = plotState.getOwner();
        EntityCollection entities = owner.getEntityCollection();
        if (entities != null) {
            entities.add(new AxisLabelEntity(this, hotspot, this.labelToolTip, this.labelURL));
        }
    }

    return state;
}

private void drawRotatedLabel(String label, Graphics2D g2, float x, float y, double angle, Rectangle2D labelBounds) {
    AffineTransform t = AffineTransform.getRotateInstance(angle, labelBounds.getCenterX(), labelBounds.getCenterY());
    Shape rotatedLabelBounds = t.createTransformedShape(labelBounds);
    labelBounds = rotatedLabelBounds.getBounds2D();
    TextUtilities.drawRotatedString(label, g2, x, y, TextAnchor.CENTER, angle, TextAnchor.CENTER);
}
